// ================================================================
// WF-1 v2 · PROFILE INTAKE with self-improving loop
// 1. security  2. load style guide + voice profile from DB
// 3. Haiku: parse profile + classify (§8)  4. retrieve 5 best
//    similar past drafts  5. Sonnet: draft cold outreach with
//    style guide + retrieved examples  6. save contact
// 7. log draft to message_examples (feedback comes later via WF-3)
// 8. rotate recent-openers list  9. reply to extension
// ================================================================

const helpers = this.helpers;
const payload = $json.body || {};

// ---------- 1. SECURITY ----------
if (payload.secret !== $env.LINKUP_SECRET) {
  throw new Error('Unauthorized — wrong or missing secret');
}

const pageText = String(payload.page_text || '').slice(0, 6000);
const linkedinUrl = String(payload.url || '').split('?')[0].replace(/\/+$/, '');
if (!pageText || !linkedinUrl.includes('linkedin.com/in/')) {
  throw new Error('This does not look like a LinkedIn profile page');
}

// ---------- HELPERS ----------
async function askClaude(model, maxTokens, temperature, systemPrompt, userPrompt) {
  let res;
  try {
    res = await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': $env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        model: model,
        max_tokens: maxTokens,
        // sonnet-5 thinks by default and rejects custom temperatures — omit when null
        temperature: temperature === null ? undefined : temperature,
        system: systemPrompt || undefined,
        messages: [{ role: 'user', content: userPrompt }],
      }),
    });
  } catch (e) {
    // Dig the real API error out of wherever this n8n version hides it
    const detail = JSON.stringify(
      (e.response && (e.response.data || e.response.body)) ||
      (e.cause && e.cause.response && e.cause.response.data) ||
      e.description || e.message
    );
    throw new Error('CLAUDE call failed (model ' + model + '): ' + detail);
  }
  if (typeof res === 'string') res = JSON.parse(res);
  const textBlock = (res.content || []).find((b) => b.type === 'text');
  if (!textBlock || !textBlock.text) {
    throw new Error('Unexpected Claude reply: ' + JSON.stringify(res).slice(0, 400));
  }
  return textBlock.text;
}

function extractJson(text) {
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('Claude did not return JSON. Got: ' + text.slice(0, 200));
  return JSON.parse(match[0]);
}

async function supabase(method, path, body, extraHeaders) {
  let res;
  try {
    res = await helpers.httpRequest({
      method: method,
      url: $env.SUPABASE_URL + path,
      headers: {
        apikey: $env.SUPABASE_SERVICE_KEY,
        Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
        'content-type': 'application/json',
        ...(extraHeaders || {}),
      },
      body: body === undefined ? undefined : JSON.stringify(body),
    });
  } catch (e) {
    const detail = (e.response && e.response.data) ? JSON.stringify(e.response.data) : e.message;
    throw new Error('SUPABASE call failed (' + method + ' ' + path + '): ' + detail);
  }
  if (typeof res === 'string' && res.trim().length) res = JSON.parse(res);
  return res;
}

// ---------- 2. LOAD STYLE GUIDE + VOICE PROFILE ----------
const cfg = await supabase('GET', '/rest/v1/prompt_config?id=eq.1&select=content');
if (!cfg || !cfg.length) {
  throw new Error('prompt_config is empty — paste your style guide (upgrade guide Part 2)');
}
const styleGuide = cfg[0].content;

const vpRows = await supabase('GET', '/rest/v1/voice_profile?id=eq.1&select=*');
const vp = (vpRows && vpRows[0]) || {};

// ---------- 3. PARSE + CLASSIFY (Haiku, temp 0 — §8) ----------
const parsePrompt = `You extract structured data from LinkedIn profile page text
and classify the person for outreach targeting.
Return ONLY valid JSON:
{"contact": {"full_name": string, "headline": string|null, "company": string|null,
  "role": string|null, "previous_companies": string[], "college": string|null,
  "location": string|null, "is_bits_alum": boolean, "notable_points": string[]},
 "classification": {
  "is_bits_alum": boolean,
  "seniority_tier": "peer"|"mid"|"senior",
  "side": "business"|"engineering",
  "track_match": "product"|"finance",
  "honorific": "sir"|"maam"|"none",
  "special_flag": "firstclub"|"recruiter"|"none"},
 "profile_snippet": string}

Rules:
- is_bits_alum: true ONLY if BITS Pilani (any campus, any program) appears in education.
- seniority_tier: peer = 0-2 yrs exp or student; mid = 3-14 yrs IC/Manager;
  senior = 15+ yrs OR Director/VP/Principal/Head/SVP/C-suite.
- side: engineering = SWE/SDE/EM/QA/DataEng/Architect/DevOps/MLEng/design-craft;
  business = everything product/growth/strategy/GTM/analytics/finance/ops.
- track_match: finance = IB/risk/credit/BFSI/insurance/banking; else product.
- honorific: sir/maam ONLY when seniority_tier = senior.
- profile_snippet: <=500 chars of the MOST hook-worthy specifics
  (companies, transitions, projects, posts, milestones).
Use null for missing fields. Do NOT invent data.

PAGE TEXT:
${pageText}`;

const parsed = extractJson(
  await askClaude('claude-haiku-4-5-20251001', 1000, 0, null, parsePrompt)
);
const contact = parsed.contact;
const cls = parsed.classification;

// ---------- 4. RETRIEVE 5 BEST SIMILAR PAST DRAFTS ----------
// Metadata match beats embeddings at this scale: same message type,
// same track, same seniority tier, only drafts that WORKED, best first.
const GOOD = 'outcome=in.(used_as_is,edited_minor,got_reply_positive,referral_given)';
const SELECT = 'select=profile_snippet,draft_sent,draft_original,outcome,quality_score';
const BASE = '/rest/v1/message_examples?' + SELECT + '&message_type=eq.cold_outreach&'
           + GOOD + '&quality_score=gte.0.6&order=quality_score.desc,captured_at.desc&limit=5';

let examples = await supabase('GET', BASE
  + '&classification->>track_match=eq.' + cls.track_match
  + '&classification->>seniority_tier=eq.' + cls.seniority_tier);
if (!examples || !examples.length) {           // relax: drop the tier filter
  examples = await supabase('GET', BASE
    + '&classification->>track_match=eq.' + cls.track_match);
}
if (!examples || !examples.length) {           // relax again: any good example
  examples = await supabase('GET', BASE);
}

// ---------- 5. BUILD RUNTIME CONTEXT + DRAFT (Sonnet, temp 0.4) ----------
let runtime = '';
if (examples && examples.length) {
  runtime += '\n\n## RUNTIME CONTEXT (learned — updated every call)\n';
  runtime += '\n### Similar past drafts that worked (emulate the voice; NEVER copy sentences verbatim):\n';
  examples.forEach((e, i) => {
    runtime += '\nExample ' + (i + 1) + ' (outcome: ' + e.outcome + ', quality: ' + e.quality_score + ')\n'
             + 'Profile: ' + (e.profile_snippet || '') + '\n'
             + 'Draft used: ' + (e.draft_sent || e.draft_original) + '\n---\n';
  });
}
if (vp.recent_hook_openers && vp.recent_hook_openers.length) {
  runtime += '\n### Recently used opening lines (do NOT repeat these verbatim):\n- '
           + vp.recent_hook_openers.slice(-10).join('\n- ') + '\n';
}
if (vp.learned_bans && vp.learned_bans.length) {
  runtime += '\n### Additional learned bans (never generate, on top of the style-guide bans):\n- '
           + vp.learned_bans.join('\n- ') + '\n';
}
if (vp.learned_preferences && Object.keys(vp.learned_preferences).length) {
  runtime += '\n### Learned preferences (Sagnik edits toward these — use the right side):\n'
           + JSON.stringify(vp.learned_preferences) + '\n';
}

const task = `TASK: Write ONE cold-outreach LinkedIn message to this person,
following the style guide's template structure (§5) and variation rules (§6) exactly.

CLASSIFICATION (§8, already computed): ${JSON.stringify(cls)}
PARSED PROFILE: ${JSON.stringify(contact)}
HOOK MATERIAL (profile snippet): ${parsed.profile_snippet}

Remember: run the §12 checklist before answering.
Output ONLY the message (plus a single targeting-note line at the very top
ONLY if the profile is genuinely ambiguous).`;

const message = (
  // null temp = model default (required for thinking models); 2000 tokens
  // because thinking spends output tokens before the actual message
  await askClaude('claude-sonnet-5', 2000, null, styleGuide + runtime, task)
).trim();

// ---------- 6. SAVE CONTACT (upsert; get its id back) ----------
const row = {
  linkedin_url: linkedinUrl,
  full_name: contact.full_name,
  headline: contact.headline,
  company: contact.company,
  role: contact.role,
  previous_companies: contact.previous_companies || [],
  college: contact.college,
  location: contact.location,
  is_bits_alum: !!contact.is_bits_alum,
  connection_date: new Date().toISOString().slice(0, 10),
  first_message: message,
  status: 'accepted',
  raw_profile_text: pageText,
  updated_at: new Date().toISOString(),
};
const saved = await supabase(
  'POST', '/rest/v1/contacts?on_conflict=linkedin_url&select=id', [row],
  { Prefer: 'resolution=merge-duplicates,return=representation' }
);
const contactId = saved[0].id;

// ---------- 7. LOG THE DRAFT (outcome stays null until you give feedback) ----------
const ex = await supabase(
  'POST', '/rest/v1/message_examples?select=id',
  [{
    contact_id: contactId,
    message_type: 'cold_outreach',
    classification: cls,
    profile_snippet: parsed.profile_snippet,
    draft_original: message,
  }],
  { Prefer: 'return=representation' }
);
const exampleId = ex[0].id;

// ---------- 8. ROTATE RECENT OPENERS + BUMP COUNTER ----------
const firstLine = (message.split('\n').find((l) => l.trim()) || '').slice(0, 160);
const openers = (vp.recent_hook_openers || []).concat([firstLine]).slice(-20);
await supabase('PATCH', '/rest/v1/voice_profile?id=eq.1', {
  recent_hook_openers: openers,
  total_drafts: (vp.total_drafts || 0) + 1,
  updated_at: new Date().toISOString(),
});

// ---------- 9. REPLY TO THE EXTENSION ----------
return [{ json: {
  ok: true,
  contact: contact,
  classification: cls,
  message: message,
  example_id: exampleId,   // the extension sends this back with your feedback
} }];
